var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"충성. 오랜만입니다, 대통령님.","JPN":"敬礼。ご無沙汰しております、大統領閣下。","ENG":"Hello, Mister President. It’s been a long time.","TWN":"忠誠！總統好久不見。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"……이거 놀랍군. 자네가 먼저 연락을 하다니.","JPN":"……これは驚いたな。君から連絡が来るとは。","ENG":"My... It's a surprise. I never expected you to call first.","TWN":"……真是意外，你竟然會主動跟我聯絡。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"목소리 듣기도 어려웠던 사람이 무슨 바람이 분 건가?","JPN":"声も滅多に聞けない者がどういう風の吹き回しだ。","ENG":"Considering how rarely you call, to what do I owe this pleasure?","TWN":"平常光是要聽到你的聲音都很難，是什麼風把你吹來的？"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자주 인사드리지 못한 건 사과드리겠습니다.","JPN":"頻繁にご連絡できなかったことはお詫び申し上げます。","ENG":"I apologize for not being able to contact you more often.","TWN":"很抱歉，久久才向總統問安。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 저와 자주 연락하시는 게 정치적으로 좋은 일은 아니란 걸 모르시진 않겠죠.","JPN":"ですが、私とたびたび連絡をとるのが政治的によくないということはご存じではありませんか。","ENG":"However, you must be aware that my contacting you frequently does not look good from a political standpoint.","TWN":"但我想總統也很清楚，太常和我聯絡，就政治層面而言並非好事。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제 나름대로의 배려였다고 생각해 주시면 감사하겠습니다.","JPN":"私なりの気遣いだったとお考えください。","ENG":"Please consider it an act of consideration on my part.","TWN":"就當作是我自以為的體貼吧，還請見諒。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"좋아. 틀린 말은 아니지.","JPN":"いいだろう。間違ってはいない。","ENG":"I understand. You aren’t wrong about that.","TWN":"好吧，你說的也有道理。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그래서 오늘은 무슨 일인가?","JPN":"で、今日はどうした？","ENG":"So, what did you call me for?","TWN":"所以到底是什麼事？"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저도 대통령님의 간접적인 화법에 맞춰드리고 싶지만 그럴 여유가 없군요.","JPN":"私も大統領閣下の間接的な話し方にお付き合いしたいところですが、その余裕はございません。","ENG":"I would have preferred to approach this with you in a gentler manner, but I am unfortunately out of time.","TWN":"我也想配合總統先寒暄幾句，但情況有點緊急。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"단도직입적으로 말씀드리죠. 감찰부대가 제가 있는 기지를 공격하고 있습니다.","JPN":"単刀直入にお話しいたします。監察部隊が私のいる基地を攻撃しています。","ENG":"So I’ll get straight to the point. The Inspection Corps are currently attacking my base.","TWN":"請恕我就直接進入主題，監察組正在攻擊我所在的基地。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"何だと……？","ENG":"What...?!","TWN":"你說什麼……？"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"국방부 네트워크의 제 ID도 접근이 차단됐군요.","JPN":"私の国防省ネットワークのIDもアクセスが拒否されています。","ENG":"I have also found that my ID has lost access to the National Defense network.","TWN":"而且國防部的網路也已經封鎖我的帳號，"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아마도 제가 국가의 적으로 규정된 모양입니다.","JPN":"たぶん私を国家の敵と規定したのでしょう。","ENG":"It seems that I have been designated as an enemy of the state.","TWN":"看來我已經被判定是國家的敵人。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"말도 안되는 소리, 자네가 국가의 적이 될 리가 없잖나?","JPN":"あり得ない、君が国家の敵のはずがないだろう？","ENG":"That’s outrageous! There’s no way that you would be an enemy of the state!","TWN":"荒謬！你怎麼可能會是國家的敵人？！"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇지 않으면 국가의 적일 가능성이 있다고 의심 받았다, 정도로 해 두죠.","JPN":"それでは国家の敵である可能性を疑われたとでもしておきましょう。","ENG":"Or, alternatively, I could be under suspicion of being a potential enemy of the state.","TWN":"要不就先假設我被懷疑有可能成為國家的敵人吧。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"명분이야 어쨌든, 지금 제 발을 묶고 시간을 낭비하게만 하면 저들을 움직인 자들의 목적은 충분히 달성될 테니까요.","JPN":"名分はどうであれ、今私の足を引っ張り、時間さえ無駄にさせれば彼らを動かした者の目的は十分達成するわけですので。","ENG":"Whatever the reason, whoever is behind this will be able to achieve their goal if I allow them to hold me down and waste my time.","TWN":"不管罪名是什麼，現在只要困住我，消耗我們的時間，對方就可以達到他們的目的。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대통령님.","JPN":"閣下。","ENG":"Mister President.","TWN":"總統，"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저는 국민을 지키는 군인으로서 무엇이 되었든 국민의 명령에 복종할 준비가 되어 있습니다.","JPN":"私は国民を守る軍人として、何であろうとも国民の命令に従う準備ができています。","ENG":"As a soldier who serves the people, I am prepared to follow the orders of the people.","TWN":"我身為保護國民的軍人，無論會變成什麼樣，我都已經做好服從國民命令的準備。"},"stage":{"bg":"MAINSTREAM_5502010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};